+                layers: mb.canonical.layers.clone(),
+            },
+            fingerprint: ma.fingerprint,
+        };
+
+        // Fingerprint-only equivalence says "equal", but PartialEq must remain exact.
+        assert!(ma.equivalent(&spoof));
+        assert_ne!(ma, spoof);
